using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences to include in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;

    public int OriginalSentenceCount { get; set; }

    public int SummarySentenceCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizationService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "it", "this",
        "that", "from", "as", "be", "has", "have", "had", "not", "no",
        "do", "does", "did", "will", "would", "could", "should", "may",
        "might", "can", "shall", "its", "his", "her", "their", "our",
        "my", "your", "he", "she", "they", "we", "you", "i", "me",
        "him", "them", "us", "who", "which", "what", "when", "where",
        "how", "if", "then", "than", "so", "just", "about", "into",
        "through", "after", "before", "between", "under", "over", "such",
        "each", "every", "all", "both", "few", "more", "most", "other",
        "some", "any", "only", "own", "same", "very", "also", "been"
    };

    /// <summary>
    /// Produces an extractive summary by scoring sentences based on word frequency
    /// and returning the top-ranked sentences in their original order.
    /// </summary>
    public string Summarize(string text, int maxSentences)
    {
        var sentences = SplitIntoSentences(text);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var sentenceScores = ScoreSentences(sentences, wordFrequencies);

        var topIndices = sentenceScores
            .Select((score, index) => (score, index))
            .OrderByDescending(x => x.score)
            .Take(maxSentences)
            .Select(x => x.index)
            .OrderBy(i => i); // preserve original order

        var summary = string.Join(" ", topIndices.Select(i => sentences[i]));
        return summary;
    }

    public int CountSentences(string text) => SplitIntoSentences(text).Count;

    private static List<string> SplitIntoSentences(string text)
    {
        var raw = SentenceBoundary().Split(text.Trim());
        return raw
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in TokenizeWords(sentence))
            {
                if (StopWords.Contains(word) || word.Length < 2)
                    continue;

                if (!freq.TryAdd(word, 1))
                    freq[word]++;
            }
        }

        return freq;
    }

    private static List<double> ScoreSentences(
        List<string> sentences,
        Dictionary<string, int> wordFrequencies)
    {
        var maxFreq = wordFrequencies.Values.DefaultIfEmpty(1).Max();

        return sentences.Select(sentence =>
        {
            var words = TokenizeWords(sentence);
            if (words.Length == 0) return 0.0;

            var score = words
                .Where(w => !StopWords.Contains(w) && w.Length >= 2)
                .Sum(w => wordFrequencies.GetValueOrDefault(w, 0) / (double)maxFreq);

            // Normalize by word count to avoid bias toward long sentences
            return score / words.Length;
        }).ToList();
    }

    private static string[] TokenizeWords(string sentence)
    {
        return WordToken().Matches(sentence)
            .Select(m => m.Value.ToLowerInvariant())
            .ToArray();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceBoundary();

    [GeneratedRegex(@"\b[a-zA-Z']+\b", RegexOptions.Compiled)]
    private static partial Regex WordToken();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizationService _service;

    public SummarizeController(DocumentSummarizationService service)
    {
        _service = service;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var originalCount = _service.CountSentences(request.DocumentText);
        var summary = _service.Summarize(request.DocumentText, request.MaxSentences);
        var summaryCount = _service.CountSentences(summary);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = originalCount,
            SummarySentenceCount = summaryCount
        });
    }
}

